     9→const PAGE_SIZE = siteConfig.pagination.flows;
    10→
    11→export function generateStaticParams() {
    12→  if (siteConfig.features?.flow?.enabled === false) return [{ page: '2' }];
    13→  const allFlows = getAllFlows();
    14→  const totalPages = Math.ceil(allFlows.length / PAGE_SIZE);
    15→
    16→  // Always generate at least page 2 for static export compatibility
    17→  const pageCount = Math.max(1, totalPages - 1);
    18→  return Array.from({ length: pageCount }, (_, i) => ({
    19→    page: (i + 2).toString(),
    20→  }));
    21→}
    22→
    23→export const dynamicParams = false;
    24→
    25→export async function generateMetadata({ params }: { params: Promise<{ page: string }> }): Promise<Metadata> {
    26→  const { page } = await params;
    27→  return {
    28→    title: `${t('flow')} - ${page} | ${resolveLocale(siteConfig.title)}`,
    29→  };
    30→}
    31→
    32→export default async function FlowsPaginatedPage({ params }: { params: Promise<{ page: string }> }) {
    33→  if (siteConfig.features?.flow?.enabled === false) notFound();
    34→  const { page: pageStr } = await params;
    35→  const page = parseInt(pageStr, 10);
    36→  const allFlows = getAllFlows();
    37→  const totalPages = Math.ceil(allFlows.length / PAGE_SIZE);
    38→
    39→  if (page > totalPages) notFound();
    40→
    41→  const entryDates = allFlows.map(f => f.date);
    42→  const tags = getFlowTags();
    43→
    44→  const start = (page - 1) * PAGE_SIZE;
    45→  const end = start + PAGE_SIZE;
    46→  const flows = allFlows.slice(start, end);
    47→
    48→  return (
    49→    <div className="layout-main">
    50→      <FlowHubTabs subtitle={tWith('page_of_total', { page, total: totalPages })} />
    51→      <FlowContent
    52→        flows={flows}
    53→        entryDates={entryDates}
    54→        tags={tags}
    55→        pagination={{ currentPage: page, totalPages, basePath: '/flows' }}
    56→      />
    57→    </div>
    58→  );
    59→}
