   681→export function getRelatedPosts(currentSlug: string, limit: number = 3): PostData[] {
   682→  const allPosts = getAllPosts();
   683→  const currentPost = allPosts.find(p => p.slug === currentSlug);
   684→
   685→  if (!currentPost) return [];
   686→
   687→  const related = allPosts
   688→    .filter(post => post.slug !== currentSlug)
   689→    .map(post => {
   690→      let score = 0;
   691→      const commonTags = post.tags.filter(tag => currentPost.tags.includes(tag));
   692→      score += commonTags.length * 2;
   693→
   694→      if (post.category === currentPost.category && post.category !== 'Uncategorized') {
   695→        score += 1;
   696→      }
   697→
   698→      return { post, score };
   699→    })
   700→    .filter(item => item.score > 0)
   701→    .sort((a, b) => b.score - a.score)
   702→    .slice(0, limit)
   703→    .map(item => item.post);
   704→
   705→  return related;
   706→}
