  1042→// ─── Flows (Daily Notes) ────────────────────────────────────────────────────
  1043→
  1044→const FlowSchema = z.object({
  1045→  title: z.string().optional(),
  1046→  date: z.union([z.string(), z.date()]).transform(val => new Date(val).toISOString().split('T')[0]).optional(),
  1047→  tags: z.array(z.string()).optional().default([]),
  1048→  draft: z.boolean().optional().default(false),
