'use client';

import { useState, useMemo, type ReactNode } from 'react';
import Link from 'next/link';
import { useLanguage } from '@/components/LanguageProvider';
import { padNumber } from '@/lib/format-utils';

interface FlowCalendarSidebarProps {
  entryDates: string[];
  currentDate?: string;
  tags?: Record<string, number>;
  selectedTag?: string | null;
  onTagSelect?: (tag: string) => void;
  breadcrumb?: ReactNode;
}

const WEEKDAYS = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];
const MONTH_NAMES = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

export default function FlowCalendarSidebar({ entryDates, currentDate, tags, selectedTag, onTagSelect, breadcrumb }: FlowCalendarSidebarProps) {
  const { t } = useLanguage();
  const initialDate = currentDate ? new Date(currentDate + 'T00:00:00') : new Date();
  const [viewYear, setViewYear] = useState(initialDate.getFullYear());
  const [viewMonth, setViewMonth] = useState(initialDate.getMonth());
  const [showBrowse, setShowBrowse] = useState(false);

  const today = new Date();
  const todayStr = today.toISOString().split('T')[0];
  const isViewingCurrentMonth = viewYear === today.getFullYear() && viewMonth === today.getMonth();

  function goToToday() {
    setViewYear(today.getFullYear());
    setViewMonth(today.getMonth());
  }

  const entrySet = useMemo(() => new Set(entryDates), [entryDates]);

  const firstDay = new Date(viewYear, viewMonth, 1).getDay();
  const daysInMonth = new Date(viewYear, viewMonth + 1, 0).getDate();

  const monthLabel = new Date(viewYear, viewMonth).toLocaleDateString('en-US', {
    month: 'long',
    year: 'numeric',
  });

  // Build year/month tree from entryDates for browse panel
  const yearMonthTree = useMemo(() => {
    const tree: Record<number, Record<number, number>> = {};
    for (const dateStr of entryDates) {
      const [y, m] = dateStr.split('-').map(Number);
      if (!tree[y]) tree[y] = {};
      tree[y][m] = (tree[y][m] || 0) + 1;
    }
    return tree;
  }, [entryDates]);

  const sortedYears = useMemo(
    () => Object.keys(yearMonthTree).map(Number).sort((a, b) => b - a),
    [yearMonthTree]
  );

  function prevMonth() {
    if (viewMonth === 0) {
      setViewYear(viewYear - 1);
      setViewMonth(11);
    } else {
      setViewMonth(viewMonth - 1);
    }
  }

  function nextMonth() {
    if (viewMonth === 11) {
      setViewYear(viewYear + 1);
      setViewMonth(0);
    } else {
      setViewMonth(viewMonth + 1);
    }
  }

  const days = useMemo(() => {
    const cells: (number | null)[] = [];
    for (let i = 0; i < firstDay; i++) cells.push(null);
    for (let d = 1; d <= daysInMonth; d++) cells.push(d);
    return cells;
  }, [firstDay, daysInMonth]);

  return (
    <aside className="hidden lg:block sticky top-20 self-start w-[280px] max-h-[calc(100vh-6rem)]">
      {breadcrumb && <div className="mb-4">{breadcrumb}</div>}
      <div className="border border-muted/20 rounded-lg p-4">
        {/* Month navigation */}
        <div className="flex items-center justify-between mb-3">
          <button
            onClick={prevMonth}
            className="p-1 text-muted hover:text-accent transition-colors"
            aria-label="Previous month"
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M15 18l-6-6 6-6" /></svg>
          </button>
          <div className="flex items-center gap-1.5">
            <span className="text-sm font-medium text-heading">{monthLabel}</span>
            {!isViewingCurrentMonth && (
              <button
                onClick={goToToday}
                className="text-[10px] px-1.5 py-0.5 rounded border border-muted/20 text-muted hover:border-accent hover:text-accent transition-colors"
                aria-label="Go to today"
              >
                {t('today')}
              </button>
            )}
          </div>
          <button
            onClick={nextMonth}
            className="p-1 text-muted hover:text-accent transition-colors"
            aria-label="Next month"
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18l6-6-6-6" /></svg>
          </button>
        </div>

        {/* Weekday headers */}
        <div className="grid grid-cols-7 gap-0 mb-1">
          {WEEKDAYS.map(d => (
            <div key={d} className="text-center text-[10px] font-medium text-muted py-1">{d}</div>
          ))}
        </div>

        {/* Day cells */}
        <div className="grid grid-cols-7 gap-0">
          {days.map((day, i) => {
            if (day === null) return <div key={`empty-${i}`} />;

            const dateStr = `${viewYear}-${padNumber(viewMonth + 1)}-${padNumber(day)}`;
            const hasEntry = entrySet.has(dateStr);
            const isToday = dateStr === todayStr;
            const isCurrent = dateStr === currentDate;

            const baseClasses = 'relative flex flex-col items-center justify-center h-8 text-xs rounded-md transition-colors';

            if (isCurrent) {
              return (
                <Link
                  key={dateStr}
                  href={`/flows/${viewYear}/${padNumber(viewMonth + 1)}/${padNumber(day)}`}
                  className={`${baseClasses} bg-accent text-white font-bold no-underline`}
                >
                  {day}
                </Link>
              );
            }

            if (hasEntry) {
              return (
                <Link
                  key={dateStr}
                  href={`/flows/${viewYear}/${padNumber(viewMonth + 1)}/${padNumber(day)}`}
                  className={`${baseClasses} text-foreground hover:bg-accent/10 font-medium no-underline ${isToday ? 'ring-1 ring-accent' : ''}`}
                >
                  {day}
                  <span className="absolute bottom-0.5 w-1 h-1 rounded-full bg-accent" />
                </Link>
              );
            }

            return (
              <div
                key={dateStr}
                className={`${baseClasses} text-muted/50 ${isToday ? 'ring-1 ring-accent' : ''}`}
              >
                {day}
              </div>
            );
          })}
        </div>

        {/* Browse toggle */}
        <div className="mt-3 pt-3 border-t border-muted/20">
          <button
            onClick={() => setShowBrowse(!showBrowse)}
            className="flex items-center gap-1 text-xs text-muted hover:text-accent transition-colors w-full"
          >
            <svg
              width="12"
              height="12"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              className={`transition-transform ${showBrowse ? 'rotate-90' : ''}`}
            >
              <path d="M9 18l6-6-6-6" />
            </svg>
            {t('browse')}
          </button>

          {showBrowse && (
            <div className="mt-2 space-y-2 max-h-48 overflow-y-auto">
              {sortedYears.map(year => {
                const months = yearMonthTree[year];
                const yearTotal = Object.values(months).reduce((a, b) => a + b, 0);
                const isCurrentYear = year === viewYear;

                return (
                  <div key={year}>
                    <Link
                      href={`/flows/${year}`}
                      className={`flex items-center justify-between text-xs no-underline px-1 py-0.5 rounded hover:bg-accent/10 ${
                        isCurrentYear ? 'text-accent font-medium' : 'text-foreground'
                      }`}
                    >
                      <span>{year}</span>
                      <span className="text-muted text-[10px]">{yearTotal}</span>
                    </Link>
                    <div className="ml-3 mt-0.5 space-y-0.5">
                      {Object.keys(months)
                        .map(Number)
                        .sort((a, b) => a - b)
                        .map(m => {
                          const isCurrentMonth = isCurrentYear && m - 1 === viewMonth;
                          return (
                            <Link
                              key={m}
                              href={`/flows/${year}/${padNumber(m)}`}
                              className={`flex items-center justify-between text-xs no-underline px-1 py-0.5 rounded hover:bg-accent/10 ${
                                isCurrentMonth ? 'text-accent font-medium' : 'text-muted'
                              }`}
                            >
                              <span>{MONTH_NAMES[m - 1]}</span>
                              <span className="text-[10px]">{months[m]}</span>
                            </Link>
                          );
                        })}
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

      </div>

      {/* Tags */}
      {tags && Object.keys(tags).length > 0 && (
        <div className="mt-3 border border-muted/20 rounded-lg p-4">
          <div className="text-xs font-medium text-muted mb-2">{t('tags')}</div>
          <div className="flex flex-wrap gap-1.5">
            {Object.entries(tags)
              .sort((a, b) => b[1] - a[1])
              .map(([tag]) => (
                <button
                  key={tag}
                  onClick={() => onTagSelect?.(tag)}
                  className={`inline-flex items-center px-2 py-0.5 text-xs rounded-full border transition-colors ${
                    selectedTag === tag
                      ? 'bg-accent text-white border-accent'
                      : 'border-muted/20 text-muted hover:border-accent hover:text-accent'
                  }`}
                >
                  {tag}
                </button>
              ))}
          </div>
        </div>
      )}
    </aside>
  );
}

import { getAllFlows, getFlowsByYear, getFlowTags } from '@/lib/markdown';
import { siteConfig } from '../../../../site.config';
import { Metadata } from 'next';
import { notFound } from 'next/navigation';
import Link from 'next/link';
import { t, tWith, resolveLocale } from '@/lib/i18n';
import PageHeader from '@/components/PageHeader';
import FlowContent from '@/components/FlowContent';

export function generateStaticParams() {
  if (siteConfig.features?.flow?.enabled === false) return [{ year: '_' }];
  const allFlows = getAllFlows();
  if (allFlows.length === 0) return [{ year: '_' }];
  const years = new Set(allFlows.map(f => f.slug.split('/')[0]));
  return Array.from(years).map(year => ({ year }));
}

export const dynamicParams = false;

export async function generateMetadata({ params }: { params: Promise<{ year: string }> }): Promise<Metadata> {
  const { year } = await params;
  return {
    title: `${tWith('flows_in_year', { year })} | ${resolveLocale(siteConfig.title)}`,
  };
}

export default async function FlowsYearPage({ params }: { params: Promise<{ year: string }> }) {
  if (siteConfig.features?.flow?.enabled === false) notFound();
  const { year } = await params;
  const flows = getFlowsByYear(year);
  if (flows.length === 0) notFound();

  const allFlows = getAllFlows();
  const entryDates = allFlows.map(f => f.date);
  const tags = getFlowTags();

  // Build month counts for this year
  const monthCounts: Record<string, number> = {};
  for (const flow of flows) {
    const month = flow.date.split('-')[1];
    monthCounts[month] = (monthCounts[month] || 0) + 1;
  }
  const sortedMonths = Object.keys(monthCounts).sort();

  const monthNames = [
    'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
    'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec',
  ];

  const breadcrumb = (
    <div className="space-y-2">
      <nav aria-label="Breadcrumb" className="flex items-center gap-1.5 text-sm text-muted">
        <Link href="/flows" className="hover:text-accent no-underline">
          {t('all_flows')}
        </Link>
        <span className="text-muted/40" aria-hidden="true">›</span>
        <span className="text-foreground">{year}</span>
      </nav>
      <div className="flex flex-wrap gap-1.5">
        {sortedMonths.map(m => (
          <Link
            key={m}
            href={`/flows/${year}/${m}`}
            className="inline-flex items-center gap-1 px-2.5 py-0.5 text-xs rounded-full border border-muted/20 text-foreground hover:border-accent hover:text-accent no-underline transition-colors"
          >
            {monthNames[parseInt(m, 10) - 1]}
            <span className="text-muted text-[10px]">({monthCounts[m]})</span>
          </Link>
        ))}
      </div>
    </div>
  );

  return (
    <div className="layout-main">
      <PageHeader
        titleKey="flows_in_year"
        titleParams={{ year }}
        subtitleKey="flow_subtitle"
        subtitleParams={{ count: flows.length }}
      />

      <FlowContent
        flows={flows}
        entryDates={entryDates}
        tags={tags}
        currentDate={`${year}-01-01`}
        breadcrumb={breadcrumb}
      />
    </div>
  );
}

