interface FlowItem {
  slug: string;
  date: string;
  title: string;
  excerpt: string;
  tags: string[];
}

interface FlowContentProps {
  flows: FlowItem[];
  allFlows?: FlowItem[];
  entryDates: string[];
  tags: Record<string, number>;
  currentDate?: string;
  pagination?: {
    currentPage: number;
    totalPages: number;
    basePath: string;
  };
  breadcrumb?: ReactNode;
}

export default function FlowContent({ flows, allFlows, entryDates, tags, currentDate, pagination, breadcrumb }: FlowContentProps) {
